INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 8, "それでいいのよ！", 1201, 8, 1, 1, 0, 11120101, 0, 0, 0, "vo_minigame_1012_correct_107");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 8, "うん、OK！", 1201, 8, 1, 1, 0, 11120102, 0, 0, 0, "vo_minigame_1012_correct_108");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "いい調子ね！", 1201, 1, 1, 1, 0, 11120103, 0, 0, 0, "vo_minigame_1012_correct_109");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "じっくりでいいわ！", 1202, 1, 1, 1, 13333, 11120201, 0, 0, -1, "vo_minigame_1012_correct_115");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 9, "正解すりゃいいのよ！", 1202, 9, 1, 1, 13333, 11120202, 0, 0, -1, "vo_minigame_1012_correct_117");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "すごいわね！", 1203, 1, 1, 1, 0, 11120301, 0, 0, 0, "vo_minigame_1012_correct_118");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 5, "これ分かるの！？", 1203, 5, 1, 1, 0, 11120302, 8, 0, 0, "vo_minigame_1012_correct_119");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "これは大丈夫ね！", 1204, 1, 1, 1, 0, 11120401, 0, 0, 0, "vo_minigame_1012_correct_125");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 7, "復習バッチリね！", 1205, 7, 1, 1, 0, 11120501, 4, 0, 0, "vo_minigame_1012_correct_123");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 8, "連続で正解よ！", 1206, 8, 1, 1, 3, 11120601, 0, 0, -1, "vo_minigame_1012_correct_128");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "巻き返すわよ！", 1207, 2, 1, 1, 3, 11120701, 0, 0, -1, "vo_minigame_1012_correct_131");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "切り替えて！", 1301, 2, 1, 1, 0, 11130101, 0, 0, 0, "vo_minigame_1012_incorrect_107");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 9, "こんなこともあるわ！", 1301, 9, 1, 1, 0, 11130102, 0, 0, 0, "vo_minigame_1012_incorrect_108");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 4, "それじゃダメよ！", 1301, 4, 1, 1, 0, 11130103, 0, 0, 0, "vo_minigame_1012_incorrect_109");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 4, "タイムアップよ！", 1302, 4, 1, 1, 20000, 11130201, 0, 0, -1, "vo_minigame_1012_incorrect_116");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 5, "いや答えなさいよ！", 1302, 5, 1, 1, 20000, 11130202, 0, 0, -1, "vo_minigame_1012_incorrect_117");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 3, "難しいわね…", 1303, 3, 1, 1, 0, 11130301, 6, 0, 0, "vo_minigame_1012_incorrect_118");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 4, "難易度高すぎね…", 1303, 4, 1, 1, 0, 11130302, 0, 0, 0, "vo_minigame_1012_incorrect_119");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "忘れちゃダメよ？", 1304, 2, 1, 1, 0, 11130401, 0, 0, 0, "vo_minigame_1012_incorrect_123");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "全部が間違いじゃないわ！", 1305, 1, 1, 1, 0, 11130501, 0, 0, 0, "vo_minigame_1012_incorrect_126");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.18, 8, "フフ、全問正解よ！\nちゃんと勉強してるみたいで\n感心だわ♪", 3001, 7, 1, 1, 10, 11300101, 4, 1, 10, "vo_minigame_1012_result_1000");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.33, 7, "すごいじゃない…全問正解よ！\nま、当然といや当然よね～\nだってあたしが\n教えてやってんだから♪", 3001, 8, 1, 1, 10, 11300102, 10, 1, 10, "vo_minigame_1012_result_1001");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.41, 1, "全問正解！　パチパチパチ～♪\nこの難易度はもう完璧じゃない？\n次はもっと難しい問題に挑戦よ！\nあんたならできるって！", 3001, 8, 1, 1, 10, 11300103, 10, 1, 10, "vo_minigame_1012_result_1002");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (8.11, 8, "へえ…難しい問題を選んだのに\n全問正解できてるじゃない！！\nちょっとあんたすごすぎだわ…！\nパーフェクトよパーフェクト！", 3001, 5, 1, 1, 10, 11300104, 10, 2, 10, "vo_minigame_1012_result_1003");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (1.31, 5, "まる…まる…全部まる！\n難しい問題なのに全問正解よ…！\n驚いた…あんたいつの間に、\nこんなに勉強してたのよ！", 3001, 10, 1, 1, 10, 11300105, 0, 2, 10, "vo_minigame_1012_result_1004");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.93, 8, "ここまで完璧に正解されちゃうと\nちょっと悔しいわね…！\nけど素直に褒めてやるわ！\nえらい、えらい、えら～い！", 3001, 9, 1, 1, 10, 11300106, 0, 2, 10, "vo_minigame_1012_result_1005");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.99, 8, "すごい…あんたパーフェクトよ！\nこのままいけば次の試験、\n学年一位も夢じゃないかもね！\n楽しみだわ～♪", 3001, 5, 1, 1, 10, 11300107, 4, 3, 10, "vo_minigame_1012_result_1006");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (8.37, 7, "満点よ！　フフ、もうあんたに\n教えることはなにもないわ…！\n逆にあたしがあんたに教わりたい\nくらいよ！　…ね、先生♪", 3001, 8, 1, 1, 10, 11300108, 4, 3, 10, "vo_minigame_1012_result_1007");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.32, 5, "全・問・正・解！\n超難問揃いなのにすごいわね…！\nもしかしてだけど、\nあんたって天才！？", 3001, 7, 1, 1, 10, 11300109, 8, 3, 10, "vo_minigame_1012_result_1008");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.77, 1, "お、かなりいい点数ね～！\nあたしも教えがいがあるわ♪\nさ、まだまだ勉強するわよ！", 3001, 7, 1, 1, 7, 11300110, 4, 1, 9, "vo_minigame_1012_result_1009");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.97, 7, "うん、いい感じで点取れてるわ！\nこの調子で次は、\n満点を見せてほしいわね！", 3001, 8, 1, 1, 7, 11300111, 4, 1, 9, "vo_minigame_1012_result_1010");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.47, 1, "あ～惜しい！\nもうちょっとで満点じゃない！\n次はパーフェクトいけるわ！\n頑張りましょ！", 3001, 5, 1, 1, 7, 11300112, 0, 1, 9, "vo_minigame_1012_result_1011");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.32, 7, "すごい、かなりできてるわよ！\n難しい問題なのにやるじゃない！\nあとは目指せ、満点ね！", 3001, 8, 1, 1, 7, 11300113, 4, 2, 9, "vo_minigame_1012_result_1012");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6.49, 7, "うん、かなりいい感じよ！\nあんたには赤点の心配なんて\nまーったくなさそうね♪\nでも勉強はやめさせないけど！", 3001, 8, 1, 1, 7, 11300114, 10, 2, 9, "vo_minigame_1012_result_1013");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.56, 1, "あーあとちょっとで\n全問正解だったのに！\n難しい問題だけどあんたなら\n次は満点狙えるわ！", 3001, 5, 1, 1, 7, 11300115, 0, 2, 9, "vo_minigame_1012_result_1014");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.67, 1, "うん、ほとんど正解よ！\nこんな難しい問題なのに、\nすごいじゃない！\nやっぱりあんた只者じゃないわ！", 3001, 8, 1, 1, 7, 11300116, 10, 3, 9, "vo_minigame_1012_result_1015");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.85, 1, "着実に成長してるって感じね？\nあんたならこの難問でも、\nいつか満点取れちゃうかも…！", 3001, 7, 1, 1, 7, 11300117, 10, 3, 9, "vo_minigame_1012_result_1016");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.88, 1, "うわー惜しいわね！\nもうちょっとで満点よ？\nま、あたしでも悩む難問だから、\nこの点数は胸を張っていいわ！", 3001, 5, 1, 1, 7, 11300118, 0, 3, 9, "vo_minigame_1012_result_1017");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.12, 1, "正解率は半分くらいか～\n悪くはないんだけど、あんたなら\nこんなもんじゃないでしょ？", 3001, 3, 1, 1, 4, 11300119, 0, 1, 6, "vo_minigame_1012_result_1018");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.34, 1, "んーはっきり言っちゃうと\n中途半端な点数ね…\nまあいいわ！こっからガンガン\n点数上げていくわよ！", 3001, 9, 1, 1, 4, 11300120, 0, 1, 6, "vo_minigame_1012_result_1019");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.15, 1, "う～ん、正直物足りない点数ね！\nあんたには期待してんだから、\nもっと頑張んなさい！", 3001, 3, 1, 1, 4, 11300121, 0, 1, 6, "vo_minigame_1012_result_1020");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.3, 1, "半分くらいの正解率か\n難しい問題だから仕方ないわね…\nでもあんたはもっとできる！\nだってあたしがついてんのよ！", 3001, 9, 1, 1, 4, 11300122, 0, 2, 6, "vo_minigame_1012_result_1021");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.55, 1, "うん、そこそこできんじゃない！\n頑張って勉強して\nさらに上を目指しましょ！", 3001, 8, 1, 1, 4, 11300123, 0, 2, 6, "vo_minigame_1012_result_1022");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.19, 7, "難問なのにこの正解率は\nよくやってる方よね！\nでもこんなところで\n満足してんじゃないわよ！？", 3001, 1, 1, 1, 4, 11300124, 0, 2, 6, "vo_minigame_1012_result_1023");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.43, 1, "難問なのに半分くらい正解\nできてんじゃない♪\nこの調子でもっと学力\n上げていきましょ！", 3001, 7, 1, 1, 4, 11300125, 0, 3, 6, "vo_minigame_1012_result_1024");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "よし、平均点ってとこね！\nちゃんと勉強してるみたいで\n安心したわ～♪", 3001, 1, 1, 1, 4, 11300126, 0, 3, 6, "vo_minigame_1012_result_1025");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.72, 7, "難問揃いでこの正解率は\n大したもんよ！\nま、もっといい点取りたいんなら\n勉強、付き合ったげるわ！", 3001, 8, 1, 1, 4, 11300127, 0, 3, 6, "vo_minigame_1012_result_1026");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.5, 2, "なるほど…\nこれは教えがいがあるわね\nビシバシ鍛えてやるから\n覚悟しなさい！", 3001, 3, 1, 1, 1, 11300128, 1, 1, 3, "vo_minigame_1012_result_1027");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.25, 2, "ちょっとあんた、\n全然できてないじゃない！\n…まさかこれが本気だなんて\n言わないわよね～？", 3001, 4, 1, 1, 1, 11300129, 1, 1, 3, "vo_minigame_1012_result_1028");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.62, 2, "うーん……適当に答えても\nこれくらい正解できるわよ？\nちょっと本腰入れて\n教えないとね……！", 3001, 3, 1, 1, 1, 11300130, 0, 1, 3, "vo_minigame_1012_result_1029");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.5, 1, "…ま、まあこの問題は\nあんたには難しすぎたのかもね\nちょっとずつでいいから、\nレベルアップしていきましょ！", 3001, 9, 1, 1, 1, 11300131, 0, 2, 3, "vo_minigame_1012_result_1030");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 3, "んー結構ミスっちゃってるわね…\nこのまま続けるのもいいけど、\n簡単な問題からやり直すのも\nありかもよ～？", 3001, 3, 1, 1, 1, 11300132, 9, 2, 3, "vo_minigame_1012_result_1031");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 9, "あらら、あんたにはちょっと\n難しすぎたかしら…？\nもう一回やり直しましょうか！", 3001, 9, 1, 1, 1, 11300133, 9, 2, 3, "vo_minigame_1012_result_1032");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 3, "うーん、残念な結果ね…\n超難問だから仕方ないけど\n無理せず簡単な問題から挑戦\nしてもいいかもよ？", 3001, 3, 1, 1, 1, 11300134, 6, 3, 3, "vo_minigame_1012_result_1033");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.97, 9, "正解率はかなり悪いわね…\nまあ難しい問題だもんね…！\nそのチャレンジ精神は買うわ！", 3001, 3, 1, 1, 1, 11300135, 0, 3, 3, "vo_minigame_1012_result_1034");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.1, 1, "なんとか０点は免れたわね…\n難問揃いだけど、\nもっと頑張っていきましょ！", 3001, 3, 1, 1, 1, 11300136, 0, 3, 3, "vo_minigame_1012_result_1035");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.31, 2, "…あんたさ、０点なんて\n逆に取るの難しいわよ！？\nまさか狙ったわけじゃ\nないでしょーね～！？", 3001, 6, 1, 1, 0, 11300137, 1, 1, 0, "vo_minigame_1012_result_1036");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.1, 2, "０点って…\nあんたふざけてんの！？\nちゃんとやらないなら\n電撃魔法くらわせるわよ！？", 3001, 2, 1, 1, 0, 11300138, 1, 1, 0, "vo_minigame_1012_result_1037");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.23, 3, "もしかしたらあんたは\n勉強向いてないのかもね…\n…勉強だけがすべてじゃないわ\n違うとこで頑張りましょ！", 3001, 9, 1, 1, 0, 11300139, 9, 1, 0, "vo_minigame_1012_result_1038");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.38, 2, "怒んないから正直に言って？\n…ふざけて答えたでしょ？\nほら、正直に\n言・い・な・さ・い？", 3001, 3, 1, 1, 0, 11300140, 0, 2, 0, "vo_minigame_1012_result_1039");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.58, 2, "あんたの点数は～～…\n…はい！　０てーん！！\n…って、ふざけんなーー！！！", 3001, 8, 1, 1, 0, 11300141, 0, 2, 0, "vo_minigame_1012_result_1040");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.02, 2, "０点ってどういうこと！？\nいやあんた、逆にすごいわよ！？\n目つぶってやったとしても\n１点は取れるから！", 3001, 4, 1, 1, 0, 11300142, 1, 2, 0, "vo_minigame_1012_result_1041");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.53, 1, "あちゃー……残念だけど０点よ\nちょっと難しすぎたかもねー…\n…ま、こんなこともあるわ！\n気を落とさなくていいわよ！", 3001, 9, 1, 1, 0, 11300143, 9, 3, 0, "vo_minigame_1012_result_1042");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.4, 1, "かなりの難問とはいえ、\n０点はちょっと寂しいわね…\nでもま、逆に考えるのよ！\nあんたには伸びしろしかないわ！", 3001, 3, 1, 1, 0, 11300144, 9, 3, 0, "vo_minigame_1012_result_1043");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.35, 1, "０点かー…うん、ごめん…\n慰めの言葉が浮かばないわ！\n……ま、次があるから\n切り替えてくのよ！", 3001, 3, 1, 1, 0, 11300145, 0, 3, 0, "vo_minigame_1012_result_1044");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 8, "OK！", 1201, 8, 2, 1, 0, 12120101, 0, 0, 0, "vo_minigame_1012_correct_132");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 7, "合ってる！", 1201, 7, 2, 1, 0, 12120102, 0, 0, 0, "vo_minigame_1012_correct_133");
