INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 9, "あらら…！", 1301, 9, 2, 1, 0, 12130103, 0, 0, 0, "vo_minigame_1012_incorrect_129");
