INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "深呼吸！", 1302, 2, 2, 1, 3001, 12130203, 0, 0, 6000, "vo_minigame_1012_incorrect_132");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 3, "遅いわね…！", 1302, 3, 2, 1, 20000, 12130204, 0, 0, -1, "vo_minigame_1012_incorrect_133");
