INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 6, "忘れたの？", 1304, 6, 2, 1, 0, 12130401, 0, 0, 0, "vo_minigame_1012_incorrect_135");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "次はいける！", 1305, 2, 2, 1, 0, 12130501, 0, 0, 0, "vo_minigame_1012_incorrect_136");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 2, "ラストスパート！", 1701, 2, 2, 1, 20000, 12170101, 3, 0, 30000, "vo_minigame_1012_time_100");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 1, "もうすぐ終わりよ！", 1701, 1, 2, 1, 20000, 12170102, 3, 0, 30000, "vo_minigame_1012_time_101");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.74, 1, "はい、よくできました！\n基礎はもう完璧ね！\n次はもっと難しい問題にも\nチャレンジしちゃいなさいよ！", 3001, 7, 2, 1, 20, 12300101, 10, 1, -1, "vo_minigame_1012_result_1045");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.85, 9, "なによあんた、走り出したペンが\n止まらないって感じ？\nったくシンプルにすごいじゃない\n花丸あげるわ！", 3001, 1, 2, 1, 20, 12300102, 0, 1, -1, "vo_minigame_1012_result_1046");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 5, "すごい点数ね…！\nあんた勉強してないとか言って\nホントはめちゃくちゃやってる\nパターンのやつね！？", 3001, 5, 2, 1, 20, 12300103, 8, 1, -1, "vo_minigame_1012_result_1047");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.86, 7, "勉強の成果、\nちゃんとでてんじゃない！\nあたしもあんたの先生として、\n鼻が高いわ～♪", 3001, 8, 2, 1, 20, 12300104, 4, 2, -1, "vo_minigame_1012_result_1048");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.02, 3, "オッケー！　もう十分よ！\nこれ以上でき過ぎちゃったら、\nあたしが教える必要なくなるわ！", 3001, 5, 2, 1, 20, 12300105, 9, 2, -1, "vo_minigame_1012_result_1049");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.46, 1, "難しい問題を選んだつもりなのに\nすごい正解数ね…！\nでもまだ上がある…\n次は最難関に挑戦よ！", 3001, 5, 2, 1, 20, 12300106, 0, 2, -1, "vo_minigame_1012_result_1050");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6.85, 4, "すごいすごいとは思ってたけど、\nあんた勉強も完璧なの…？\nそりゃみんなあんたに惚れ…\nや、な、なんでもない！！", 3001, 5, 2, 1, 20, 12300107, 7, 3, -1, "vo_minigame_1012_result_1051");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.79, 9, "この問題、あたしでも悩む\n超難問なのに…\nふふっ、もう褒めるしかないわ！\n大変よくできました！", 3001, 5, 2, 1, 20, 12300108, 0, 3, -1, "vo_minigame_1012_result_1052");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 4, "別に顔赤くなんてなってない！\n頭がいい人が好きとか…\nかっこいいとか…\n…思ってないからね！", 3001, 4, 2, 1, 20, 12300109, 7, 3, -1, "vo_minigame_1012_result_1053");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 5, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 3001, 5, 2, 1, 20, 12300110, 0, 1, -1, "vo_minigame_1012_result_1054");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 5, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 3001, 5, 2, 1, 20, 12300112, 0, 2, -1, "vo_minigame_1012_result_1054");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 5, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 3001, 5, 2, 1, 20, 12300114, 0, 3, -1, "vo_minigame_1012_result_1054");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.0, 7, "おお～かなり正解できてるわね！\nこの調子でもっとすごい点\n目指しちゃうわよ！", 3001, 5, 2, 1, 15, 12300116, 10, 1, 19, "vo_minigame_1012_result_1056");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 8, "うん、バッチリいい感じよ！\nちゃんと勉強してるみたいで\n関心関心♪", 3001, 8, 2, 1, 15, 12300117, 10, 1, 19, "vo_minigame_1012_result_1057");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.01, 8, "え、こんなにいい点取れたのに\nまだ満足してないの？\nなによその向上心…\nいいじゃない！", 3001, 5, 2, 1, 15, 12300118, 0, 1, 19, "vo_minigame_1012_result_1058");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.83, 7, "スピードも正解数もいい感じよ！\nねえねえ、この調子で\nてっぺん目指しちゃう？", 3001, 8, 2, 1, 15, 12300119, 10, 2, 19, "vo_minigame_1012_result_1059");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 10, "この難易度でも\nスラスラ答えちゃうなんて…\nあんたって\nほんとすごいやつよね…！", 3001, 10, 2, 1, 15, 12300120, 0, 2, 19, "vo_minigame_1012_result_1060");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.66, 7, "これだけ正解できたら\n勉強も楽しいわよね♪\nさ、まだまだ続けるわよ～！", 3001, 8, 2, 1, 15, 12300121, 4, 2, 19, "vo_minigame_1012_result_1061");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.28, 8, "あんた、この成績\nまぐれじゃないわよね…！\nこれだけできたら\n大したもんだわ！", 3001, 5, 2, 1, 15, 12300122, 0, 3, 19, "vo_minigame_1012_result_1062");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.7, 1, "すごい！　とってもいい成績よ！\nこの難問も、あんたにかかりゃ\nイチコロってやつ？", 3001, 8, 2, 1, 15, 12300123, 0, 3, 19, "vo_minigame_1012_result_1063");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.98, 9, "あんた…もしかして\nあたしより点数いいかも？\nあ、あたしもあんたを見習って\n勉強しないとね…！", 3001, 5, 2, 1, 15, 12300124, 9, 3, 19, "vo_minigame_1012_result_1064");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.51, 1, "うん、なかなかいい点数よ！\nでもまだまだ頑張れるわよね？\nはい、次いきましょ！", 3001, 7, 2, 1, 10, 12300131, 0, 1, 14, "vo_minigame_1012_result_1067");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.16, 7, "十分優秀な成績だけど\nあんたならもっとできる！\nさ、頑張って勉強するわよ！", 3001, 1, 2, 1, 10, 12300132, 0, 1, 14, "vo_minigame_1012_result_1068");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.07, 7, "うん、いい感じね！\nこの調子で少しずつ、\n正解数を増やしてくわよ！", 3001, 8, 2, 1, 10, 12300133, 0, 1, 14, "vo_minigame_1012_result_1069");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.51, 1, "難問揃いなのに、\nけっこーいい感じじゃない！\nちゃんとできてるから\n自信もっていいわよ！", 3001, 8, 2, 1, 10, 12300134, 0, 2, 14, "vo_minigame_1012_result_1070");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "難しい問題でも基礎は大事よ！\nこの調子でどんどん\n点数上げていきましょう！", 3001, 1, 2, 1, 10, 12300135, 0, 2, 14, "vo_minigame_1012_result_1071");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.3, 7, "10問以上取れてるわね！\nえ、まだ物足りない？\nフフ、じゃあもっと上\n目指しちゃう？", 3001, 1, 2, 1, 10, 12300136, 0, 2, 14, "vo_minigame_1012_result_1072");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.47, 7, "うん、この難問でこの点数は\n十分すぎる出来よね！\nま、あんたならもっといい点\n目指しちゃうんだろうけど♪", 3001, 8, 2, 1, 10, 12300137, 0, 3, 14, "vo_minigame_1012_result_1073");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.68, 9, "はいお疲れ～\nなかなか良い点数じゃない\n…あたしも勉強しないとね！", 3001, 8, 2, 1, 10, 12300138, 0, 3, 14, "vo_minigame_1012_result_1074");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.34, 1, "おお～10問以上\n正解してんじゃない！\nあんたやっぱり\nただ者じゃないわね～", 3001, 5, 2, 1, 10, 12300139, 0, 3, 14, "vo_minigame_1012_result_1075");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6.58, 8, "うん正解率は申し分なしね！\nあとはもっと早く解ければ\nもっと点数は伸びてくわよ！\nこの調子で頑張っていきましょ！", 3001, 1, 2, 1, 10, 12300141, 0, 1, 14, "vo_minigame_1012_result_1077");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6.58, 8, "うん正解率は申し分なしね！\nあとはもっと早く解ければ\nもっと点数は伸びてくわよ！\nこの調子で頑張っていきましょ！", 3001, 1, 2, 1, 10, 12300143, 0, 2, 14, "vo_minigame_1012_result_1077");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6.58, 8, "うん正解率は申し分なしね！\nあとはもっと早く解ければ\nもっと点数は伸びてくわよ！\nこの調子で頑張っていきましょ！", 3001, 1, 2, 1, 10, 12300145, 0, 3, 14, "vo_minigame_1012_result_1077");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.24, 7, "ふ～ん、まあまあの出来だわ\n悪くはないんだけど…あんたには\nもっともっと期待してるわ～", 3001, 1, 2, 1, 5, 12300146, 0, 1, 9, "vo_minigame_1012_result_1078");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.74, 1, "うん、頑張ったけど…\n正直もっと正解できるかもね～？\nこんなのあんたには通過点！\nさらに良い点目指してみない？", 3001, 7, 2, 1, 5, 12300147, 0, 1, 9, "vo_minigame_1012_result_1079");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "まあまあな点数だけど、\n自分的に手ごたえはどう？\nダメだって思ってんなら、\nまだまだ伸びる余地ありね！", 3001, 1, 2, 1, 5, 12300148, 0, 1, 9, "vo_minigame_1012_result_1080");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.21, 1, "うん、中々の出来ね！\nでもあんたはもっといい点\n取れるはずよ！\nもっと頑張りましょうか！", 3001, 8, 2, 1, 5, 12300149, 0, 2, 9, "vo_minigame_1012_result_1081");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.46, 1, "ん～はっきり言って微妙ね！\nま、難しい問題だし、\n勉強すれば\n点数は上がっていくと思うわ！", 3001, 3, 2, 1, 5, 12300150, 0, 2, 9, "vo_minigame_1012_result_1082");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.94, 1, "ん～…\n10点には届かなかったか～\n次は10点越え目指して\n頑張ってみない？", 3001, 3, 2, 1, 5, 12300151, 0, 2, 9, "vo_minigame_1012_result_1083");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.19, 1, "はいお疲れ～\n点数的にはまあまあってとこね！\nま、超難問だし頑張ったわよ", 3001, 7, 2, 1, 5, 12300152, 0, 3, 9, "vo_minigame_1012_result_1084");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "うん、かなり難しい問題なのに\n最後までやり遂げたわね\n次はもっといい点目指してみる？", 3001, 1, 2, 1, 5, 12300153, 0, 3, 9, "vo_minigame_1012_result_1085");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.63, 1, "ちょっとミスが多かったかもね～\nでも間違えた所は復習して\n次は正解するわよー！", 3001, 3, 2, 1, 5, 12300154, 0, 3, 9, "vo_minigame_1012_result_1086");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.53, 1, "あら…あんまり良くない点数ね～\nどうしたの、調子でも悪かった？\n次はもっと頑張りましょうか", 3001, 3, 2, 1, 1, 12300155, 0, 1, 4, "vo_minigame_1012_result_1087");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 3, "ん～…正解数は\n物足りないわね～\nもうちょっと勉強の時間\n増やしちゃおっか？", 3001, 3, 2, 1, 1, 12300156, 9, 1, 4, "vo_minigame_1012_result_1088");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.15, 1, "ん～…あんたならもうちょと\nいい点取れんでしょ～？\nもっと頑張んなさいよ\n期待してやってんだからさ！", 3001, 3, 2, 1, 1, 12300157, 3, 1, 4, "vo_minigame_1012_result_1089");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 9, "ん～今のあんたには、\nこの問題は難しかったかしら…\n難易度下げてチャレンジするのも\nありかもね～？", 3001, 9, 2, 1, 1, 12300158, 9, 2, 4, "vo_minigame_1012_result_1090");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.37, 1, "あんまり出来は良くないわね～\n難しい問題だししょうがないけど\n次はもっと頑張ってほしいわ！", 3001, 3, 2, 1, 1, 12300159, 0, 2, 4, "vo_minigame_1012_result_1091");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (1.44, 1, "なるほど…\nちょっと苦手な問題が多かった？\nもう一度チャレンジ\nしてみましょうか～", 3001, 3, 2, 1, 1, 12300160, 0, 2, 4, "vo_minigame_1012_result_1092");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 3, "んん～…問題が難しすぎた？\n無理に難しい問題続けるより、\n難易度下げた方が\n勉強の効率良いかもよ～？", 3001, 3, 2, 1, 1, 12300161, 0, 3, 4, "vo_minigame_1012_result_1093");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.91, 9, "…あんまり点数取れなかったわね\nこれはあたしにも難しい問題だし\nそう落ち込まなくても大丈夫！\n次頑張りましょ！", 3001, 3, 2, 1, 1, 12300162, 3, 3, 4, "vo_minigame_1012_result_1094");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.61, 1, "ごめん、ちょっと難しすぎた？\nもう一度チャレンジするも良し、\n難易度を下げるも良し、\nあんたがやる気なら付き合うわ！", 3001, 5, 2, 1, 1, 12300163, 0, 3, 4, "vo_minigame_1012_result_1095");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.63, 2, "ちょっとあんた…\nやる気ないわよね～！？\n次こんな点数取ったら\n怒るわよ！", 3001, 4, 2, 1, 0, 12300164, 1, 1, 0, "vo_minigame_1012_result_1096");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.16, 2, "はあ…自分で何点取ったか\n分かってるわよね～…？\n０点よ０点！　舐めてんの！？", 3001, 6, 2, 1, 0, 12300165, 1, 1, 0, "vo_minigame_1012_result_1097");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 3, "うう～頭痛い…\nあんたのせいよ！\nなに０点って！\nはあ、このままじゃ赤点よ～…", 3001, 3, 2, 1, 0, 12300166, 6, 1, 0, "vo_minigame_1012_result_1098");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.75, 2, "ねえ、あんた本気でやったの？\nまさか適当にやるわけないわよね\n…分かった、\nもう一回チャレンジするのよ！", 3001, 6, 2, 1, 0, 12300167, 0, 2, 0, "vo_minigame_1012_result_1099");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.64, 2, "あ…あんた、０点よ０点…！\nあたしの教え方が悪かった…？\n…燃えてきたわ！\n絶対あんたの学力上げてやる！", 3001, 4, 2, 1, 0, 12300168, 1, 2, 0, "vo_minigame_1012_result_1100");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.73, 4, "ちょっと待って採点ミスかも…\n…いや合ってるわね。はい０点\n…って０点！？\nふざけんなーー！", 3001, 8, 2, 1, 0, 12300169, 8, 2, 0, "vo_minigame_1012_result_1101");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.32, 3, "あらら…０点よ\nま、難しい問題だしね…\n…つっても０点は無いわ！\n一問くらい正解しなさいよ！", 3001, 5, 2, 1, 0, 12300170, 1, 3, 0, "vo_minigame_1012_result_1102");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.37, 9, "残念だけど０点よ\nま、まあ前向きにとらえるなら、\n今が底よ！　どん底！\nあとは上がってくだけね！", 3001, 3, 2, 1, 0, 12300171, 9, 3, 0, "vo_minigame_1012_result_1103");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.25, 1, "…かなり出来が悪いわね\n一旦休憩しましょうか？\nリフレッシュして頭切り替えて\nもう一度頑張りましょう！", 3001, 9, 2, 1, 0, 12300172, 3, 3, 0, "vo_minigame_1012_result_1104");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 7, "さ、勉強を始めるわよ", 1001, 7, 3, 1, 0, 13100101, 0, 0, 0, "vo_minigame_1012_gamestart_100");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "よし、勉強の成果を見てやるわ！", 1001, 1, 3, 1, 0, 13100102, 0, 0, 0, "vo_minigame_1012_gamestart_101");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (1.82, 7, "じゃあ試験するわよ。はい教科書閉じて！", 1001, 1, 3, 1, 0, 13100103, 0, 0, 0, "vo_minigame_1012_gamestart_102");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 8, "やる気マンマンじゃない！", 1002, 8, 3, 1, 3, 13100201, 4, 0, -1, "vo_minigame_1012_gamestart_103");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "よし、じゃあもう一回やるわよ！", 1002, 1, 3, 1, 3, 13100202, 0, 0, -1, "vo_minigame_1012_gamestart_104");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 0, "普通の難易度よ！", 1003, 0, 3, 1, 1, 13100301, 0, 0, 1, "vo_minigame_1012_gamestart_105");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 7, "まずは基本からね！", 1003, 7, 3, 1, 1, 13100302, 0, 0, 1, "vo_minigame_1012_gamestart_106");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 10, "難しい問題に挑戦するのね！", 1003, 10, 3, 1, 2, 13100303, 0, 0, 2, "vo_minigame_1012_gamestart_107");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.67, 8, "よし、あんたならできるわ！", 1003, 1, 3, 1, 2, 13100304, 0, 0, 2, "vo_minigame_1012_gamestart_108");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 5, "あたしでも手こずる難問揃いよ…！", 1003, 5, 3, 1, 3, 13100305, 0, 0, 3, "vo_minigame_1012_gamestart_109");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "激ムズだけど頑張んなさい！", 1003, 2, 3, 1, 3, 13100306, 0, 0, 3, "vo_minigame_1012_gamestart_110");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 7, "鉄は熱いうちに打て、\n…ってね♪", 1004, 7, 3, 1, 0, 13100401, 0, 0, 0, "vo_minigame_1012_gamestart_111");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "よし、もっぺんやるわよ！", 1004, 1, 3, 1, 0, 13100402, 0, 0, 0, "vo_minigame_1012_gamestart_112");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 9, "スズナもちゃんと勉強してるみたいね～", 1005, 9, 3, 1, 0, 13100501, 0, 0, 0, "vo_minigame_1012_gamestart_113");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 3, "あんたがスズナの\n先生？　…ふーん", 1005, 3, 3, 1, 0, 13100502, 0, 0, 0, "vo_minigame_1012_gamestart_114");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "問題！", 1101, 1, 3, 1, 0, 13110101, 0, 0, 0, "vo_minigame_1012_start_100");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "いくわよ！", 1101, 1, 3, 1, 0, 13110102, 0, 0, 0, "vo_minigame_1012_start_101");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 7, "解けるかしら？", 1101, 7, 3, 1, 0, 13110103, 0, 0, 0, "vo_minigame_1012_start_102");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "次はいける！", 1102, 2, 3, 1, 0, 13110201, 0, 0, 0, "vo_minigame_1012_start_103");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "諦めないで！", 1102, 1, 3, 1, 0, 13110202, 0, 0, 0, "vo_minigame_1012_start_104");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "取り返すのよ！", 1102, 1, 3, 1, 0, 13110203, 0, 0, 0, "vo_minigame_1012_start_105");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "さあ次よ！", 1103, 1, 3, 1, 2, 13110301, 0, 0, 4, "vo_minigame_1012_start_106");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "落ち着いてね！", 1103, 1, 3, 1, 2, 13110302, 0, 0, 4, "vo_minigame_1012_start_107");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 7, "これは解ける？", 1103, 7, 3, 1, 2, 13110303, 0, 0, 4, "vo_minigame_1012_start_108");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "まだ気を抜かないで！", 1103, 2, 3, 1, 5, 13110304, 0, 0, 7, "vo_minigame_1012_start_109");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "ほら、次いくわよ！", 1103, 1, 3, 1, 5, 13110305, 0, 0, 7, "vo_minigame_1012_start_110");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 8, "まだまだ続くわよ！", 1103, 8, 3, 1, 5, 13110306, 0, 0, 7, "vo_minigame_1012_start_111");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "最後まで集中よ！", 1103, 2, 3, 1, 8, 13110307, 0, 0, 10, "vo_minigame_1012_start_112");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 8, "ラストスパート！", 1103, 8, 1, 1, 8, 13110308, 0, 0, 10, "vo_minigame_1012_start_113");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "走り切って！", 1103, 1, 1, 1, 8, 13110309, 0, 0, 10, "vo_minigame_1012_start_114");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "適当に選ぶんじゃないわよ！", 1104, 2, 3, 1, 2, 13110401, 0, 0, 2, "vo_minigame_1012_start_115");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 7, "正解はどれでしょう？", 1104, 7, 3, 1, 2, 13110402, 0, 0, 2, "vo_minigame_1012_start_116");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "正解は一つよ！", 1104, 1, 3, 1, 2, 13110403, 0, 0, 2, "vo_minigame_1012_start_117");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 3, "どっちかしら？", 1104, 3, 3, 1, 1, 13110404, 0, 0, 1, "vo_minigame_1012_start_118");
