INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.03, 4, "勉強、勉強、楽しいな～♪\n…！　は、はやく選びなさい！", 2001, 8, 3, 1, 0, 13200103, 7, 0, 0, "vo_minigame_1012_select_102");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 1, "これまでに勉強した内容を\n振り返れるわよ\n間違えちゃった問題も\nここで復習できるわ！", 4001, 1, 3, 1, 0, 13400101, 0, 0, 0, "vo_minigame_1012_archive_100");
