INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 8, "おにムズだよね～", 1303, 8, 1, 2, 0, 21130302, 0, 0, 0, "vo_minigame_1012_incorrect_219");
