INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 8, "あとちょいだったね…！", 1305, 8, 1, 2, 0, 21130501, 0, 0, 0, "vo_minigame_1012_incorrect_226");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.32, 0, "すご、全部〇じゃん…！\nこの調子で教えてくれたら\nうちも頭よくなりそー！", 3001, 6, 1, 2, 10, 21300101, 0, 1, 10, "vo_minigame_1012_result_2000");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6.5, 2, "え、〇しかなかった…？\n満点ってほんとにあるんだ…\nヒデサイマジすごい…！", 3001, 6, 1, 2, 10, 21300102, 3, 1, 10, "vo_minigame_1012_result_2001");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.1, 6, "満点じゃん！　やりー！\nもしかしてヒデサイには\n簡単過ぎた感じ？", 3001, 3, 1, 2, 10, 21300103, 5, 1, 10, "vo_minigame_1012_result_2002");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.06, 2, "ビシッと決まったね！\nヒデサイ、ベンキョー\n教えてくれてありがとー♪", 3001, 3, 1, 2, 10, 21300104, 11, 2, 10, "vo_minigame_1012_result_2003");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.45, 7, "ムズい問題もぜーんぶ正解！\n激アツじゃん！\nヒデサイ、頭よすぎ～", 3001, 3, 1, 2, 10, 21300105, 0, 2, 10, "vo_minigame_1012_result_2004");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 2, "きゃはっ、満点じゃん！\n一緒にベンキョーしてる\nうちまでいい気分！", 3001, 2, 1, 2, 10, 21300106, 11, 2, 10, "vo_minigame_1012_result_2005");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6.64, 3, "ヒデサイ、満点パーフェクト！\nこれで、もーサイツヨだね！\nそれっ、ハイタッチ～！", 3001, 2, 1, 2, 10, 21300107, 11, 3, 10, "vo_minigame_1012_result_2006");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 6, "カンペキ過ぎて\nまぶしぃんですけど！\n〇しかないってどゆこと！？", 3001, 6, 1, 2, 10, 21300108, 0, 3, 10, "vo_minigame_1012_result_2007");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.76, 7, "おにムズでも満点じゃん…！\nヒデサイセンセーマジすごい！\nこれからも頼りにしてるよ～", 3001, 6, 1, 2, 10, 21300109, 0, 3, 10, "vo_minigame_1012_result_2008");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 6, "ヒデサイ、もしかして\nよゆーな感じ？\n正解しまくりじゃん！", 3001, 6, 1, 2, 7, 21300110, 0, 1, 9, "vo_minigame_1012_result_2009");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.59, 7, "〇いっぱいで、わろ～\nてかヒデサイ教えるのうまっ！\nめちゃわかりやすかったよ♪", 3001, 2, 1, 2, 7, 21300111, 0, 1, 9, "vo_minigame_1012_result_2010");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.09, 3, "これだけ〇あったら、\nめちゃ気持ちいいね♪\n次は満点取っちゃおー！", 3001, 2, 1, 2, 7, 21300112, 11, 1, 9, "vo_minigame_1012_result_2011");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.47, 3, "満点まで、もーすぐじゃん！\nさっすがヒデサイ！\nバイブス上がってきた～", 3001, 2, 1, 2, 7, 21300113, 0, 2, 9, "vo_minigame_1012_result_2012");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 3, "きゃはっ、めちゃ解けてる～\nもー次は満点っしょ！\nテンアゲしてきたね♪", 3001, 3, 1, 2, 7, 21300114, 11, 2, 9, "vo_minigame_1012_result_2013");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "ヒデサイのおかげで\nうちもちょっちベンキョー\nわかってきたかも！", 3001, 2, 1, 2, 7, 21300115, 0, 2, 9, "vo_minigame_1012_result_2014");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.45, 2, "おにムズ問題も\n〇ばっかじゃん…！\nヒデサイ、マジ心強い！", 3001, 6, 1, 2, 7, 21300116, 0, 3, 9, "vo_minigame_1012_result_2015");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 3, "ヒデサイセンセーに\n追いつけ追い越せ！\nうちもがんばる～！", 3001, 3, 1, 2, 7, 21300117, 0, 3, 9, "vo_minigame_1012_result_2016");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.0, 3, "おにムズ問題も\nあとちょいで満点じゃん！\nもーここまできたら\nやるしかないっしょ！", 3001, 2, 1, 2, 7, 21300118, 0, 3, 9, "vo_minigame_1012_result_2017");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.92, 0, "お！　あと半分だし\nうちも、もうちっと\nがんばってみるね！", 3001, 6, 1, 2, 4, 21300119, 0, 1, 6, "vo_minigame_1012_result_2018");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.36, 3, "まだイミフな問題あるけど\n悪くないよね？\nバイブス上がってきたし\n次もっとイケんじゃない？", 3001, 0, 1, 2, 4, 21300120, 0, 1, 6, "vo_minigame_1012_result_2019");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.35, 2, "だいたい半分ぐらい？\nじゃあ、こっからだね！\n集中、集中！", 3001, 6, 1, 2, 4, 21300121, 0, 1, 6, "vo_minigame_1012_result_2020");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.13, 2, "これで半分ぐらい？\nよしっ、とりま赤点回避！\nやりー！", 3001, 0, 1, 2, 4, 21300122, 0, 2, 6, "vo_minigame_1012_result_2021");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.38, 2, "あともう半分だね！\nフレッフレッ、ヒデサイ！\nうちもがんばる～！", 3001, 0, 1, 2, 4, 21300123, 0, 2, 6, "vo_minigame_1012_result_2022");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.5, 0, "う～ん、やっぱムズいね\nでも、半分ぐらい〇だし\nイケそーな気するね！", 3001, 4, 1, 2, 4, 21300124, 0, 2, 6, "vo_minigame_1012_result_2023");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.25, 6, "だいたい半分正解？\nとゆーことは\nあと半分で満点じゃん！", 3001, 0, 1, 2, 4, 21300125, 0, 3, 6, "vo_minigame_1012_result_2024");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.14, 6, "やるじゃんヒデサイ！\nえ？　もっと上目指すの？\nじゃあうちもがんばる！", 3001, 3, 1, 2, 4, 21300126, 0, 3, 6, "vo_minigame_1012_result_2025");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.75, 2, "おにムズだったのに\n半分解けてる…！？\nヒデサイいい感じ！", 3001, 6, 1, 2, 4, 21300127, 0, 3, 6, "vo_minigame_1012_result_2026");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.53, 10, "おにムズだったね～\n…え？　これって簡単なの？\nえへへ、うそだ～？", 3001, 4, 1, 2, 1, 21300128, 5, 1, 3, "vo_minigame_1012_result_2027");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 4, "…ねーねー、ヒデサイ\nうちに合わせて\n悪い点取らなくていいんだよ？", 3001, 4, 1, 2, 1, 21300129, 9, 1, 3, "vo_minigame_1012_result_2028");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.93, 3, "ウォーミングアップは\nこんなところで…\nヒデサイ、次は\n本気出しちゃおうよ！", 3001, 0, 1, 2, 1, 21300130, 0, 1, 3, "vo_minigame_1012_result_2029");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.26, 3, "あ、ヒデサイ\nうちと点数おそろじゃん！\n一緒に赤点取っちゃおっか～♪", 3001, 0, 1, 2, 1, 21300131, 4, 2, 3, "vo_minigame_1012_result_2030");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 10, "えーっと…\nもっかい教えてくれたら\n次はもうちょい\nイケる気するよっ！", 3001, 10, 1, 2, 1, 21300132, 0, 2, 3, "vo_minigame_1012_result_2031");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.98, 0, "うちもさっぱりだった～\nどこ間違えたんだろ…？\nもっかいベンキョーしてみる？", 3001, 9, 1, 2, 1, 21300133, 5, 2, 3, "vo_minigame_1012_result_2032");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 4, "おにムズ過ぎてマジさっぱり…\nどーしよ…\nヒデサイ、助けて～", 3001, 4, 1, 2, 1, 21300134, 9, 3, 3, "vo_minigame_1012_result_2033");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 4, "赤点って感じ？\nう～ん…せっかくだし\nうちと一緒にがんばろ！", 3001, 4, 1, 2, 1, 21300135, 6, 3, 3, "vo_minigame_1012_result_2034");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.51, 10, "やっぱムズいね…\nでも０点じゃないし\nオーライっしょ！", 3001, 4, 1, 2, 1, 21300136, 11, 3, 3, "vo_minigame_1012_result_2035");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.54, 6, "よし、結果は…\nって０ってマ！？\nヒデサイ、どーしちゃったの？", 3001, 0, 1, 2, 0, 21300137, 0, 1, 0, "vo_minigame_1012_result_2036");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.08, 10, "ヒデサイ\nわざと０点取ったっしょ？\n違うの？　ほんとに～？", 3001, 2, 1, 2, 0, 21300138, 5, 1, 0, "vo_minigame_1012_result_2037");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.41, 4, "ヒデサイ、０点だね…\nうちが代わりに\nベンキョー教えてあげよっか…？", 3001, 6, 1, 2, 0, 21300139, 0, 1, 0, "vo_minigame_1012_result_2038");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.1, 8, "んーっと…\nぜんぜんわかんなかった！\nでも、ベンキョーって\nいつもそーだよね！", 3001, 10, 1, 2, 0, 21300140, 0, 2, 0, "vo_minigame_1012_result_2039");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.8, 2, "これ、うちら習ったっけ？\nヒデサイも覚えてない感じ？\nじゃあ仕方ないっしょ！\n次いこ次！", 3001, 6, 1, 2, 0, 21300141, 4, 2, 0, "vo_minigame_1012_result_2040");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.6, 8, "ねねね、全部×って\nこれはこれでレアなんじゃ？\n喜んじゃダメ？", 3001, 10, 1, 2, 0, 21300142, 3, 2, 0, "vo_minigame_1012_result_2041");
