INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.81, 3, "〇多すぎてわろ～\nスラスラ解いてくし\nまじカッコよかったよ♪", 3001, 2, 2, 2, 20, 22300101, 4, 1, -1, "vo_minigame_1012_result_2045");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.31, 2, "点数イケイケじゃん！　\nもしかして、ヒデサイには\n簡単過ぎた感じ？", 3001, 3, 2, 2, 20, 22300102, 11, 1, -1, "vo_minigame_1012_result_2046");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 3, "きゃはっ、もうバッチリだね♪\n他の問題も教えてほしーし\n次はムズいのいっちゃう？", 3001, 3, 2, 2, 20, 22300103, 11, 1, -1, "vo_minigame_1012_result_2047");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.33, 7, "ムズい問題なのに\n〇でいっぱいじゃん…！\nさっすが、ヒデサイセンセー！", 3001, 6, 2, 2, 20, 22300104, 11, 2, -1, "vo_minigame_1012_result_2048");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.73, 2, "一緒にベンキョー\nしてるだけなのに\nうちまで賢くなった気する…！\nマジありがとね", 3001, 6, 2, 2, 20, 22300105, 0, 2, -1, "vo_minigame_1012_result_2049");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 6, "これってムズい問題だよね？\nなんで簡単に解いてくの？\nヒデサイ、すごすぎ！", 3001, 6, 2, 2, 20, 22300106, 8, 2, -1, "vo_minigame_1012_result_2050");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.02, 3, "おにムズなのに\n答えるの一瞬だったね…！\nヒデサイ、頭良すぎじゃん？", 3001, 6, 2, 2, 20, 22300107, 0, 3, -1, "vo_minigame_1012_result_2051");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.24, 3, "まる、まる、はなまる～\nきゃははっ、すごっ！\nさっすがヒデサイ！\nハイタッチー！", 3001, 2, 2, 2, 20, 22300108, 11, 3, -1, "vo_minigame_1012_result_2052");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.6, 3, "これだけ教えてもらったら\nもうテストもよゆーっしょ！\nヒデサイ、マジありがとね♪", 3001, 2, 2, 2, 20, 22300109, 4, 3, -1, "vo_minigame_1012_result_2053");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.57, 10, "うちこんなの初めて見た…！\nヒデサイセンセー、神ってる！\nそだ、記念にこれ飾っとこうよ♪\nえ、それはちょっち恥ずかしい？", 3001, 6, 2, 2, 20, 22300110, 0, 1, -1, "vo_minigame_1012_result_2054");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.57, 10, "うちこんなの初めて見た…！\nヒデサイセンセー、神ってる！\nそだ、記念にこれ飾っとこうよ♪\nえ、それはちょっち恥ずかしい？", 3001, 6, 2, 2, 20, 22300112, 0, 2, -1, "vo_minigame_1012_result_2054");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.57, 10, "うちこんなの初めて見た…！\nヒデサイセンセー、神ってる！\nそだ、記念にこれ飾っとこうよ♪\nえ、それはちょっち恥ずかしい？", 3001, 6, 2, 2, 20, 22300114, 0, 3, -1, "vo_minigame_1012_result_2054");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "めちゃ問題あったのに\nバンバン答えてくし\n超頼もしかった！", 3001, 2, 2, 2, 15, 22300116, 0, 1, 19, "vo_minigame_1012_result_2056");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.23, 3, "おーさすがヒデサイ！\n〇の数も超ヒデサイだね♪\nイェーイ！", 3001, 6, 2, 2, 15, 22300117, 11, 1, 19, "vo_minigame_1012_result_2057");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.23, 2, "ヒデサイ、〇でいっぱいじゃん♪\nうちも教えてもらったとこは\nけっこー覚えてきたかも？", 3001, 3, 2, 2, 15, 22300118, 11, 1, 19, "vo_minigame_1012_result_2058");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6.0, 7, "アゲアゲな点数じゃん！\nとりま、どやっとく？\nせーの、どやぁ…！", 3001, 3, 2, 2, 15, 22300119, 10, 2, 19, "vo_minigame_1012_result_2059");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 7, "ムズい問題も\nだんだん解けてくると\nたのしーね\nちょっち感動～", 3001, 7, 2, 2, 15, 22300120, 0, 2, 19, "vo_minigame_1012_result_2060");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 6, "たくさん解いても\nヒデサイは頭パンクしないの？\nスゴ…！", 3001, 6, 2, 2, 15, 22300121, 0, 2, 19, "vo_minigame_1012_result_2061");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.06, 2, "わわっ、〇ばっかり…！\nこの調子なら\n次は20に届くんじゃない？", 3001, 6, 2, 2, 15, 22300122, 3, 3, 19, "vo_minigame_1012_result_2062");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.74, 5, "15個以上〇って…！\nおにムズなのに、すごすぎ～\nうちもがんばらなきゃ！", 3001, 6, 2, 2, 15, 22300123, 0, 3, 19, "vo_minigame_1012_result_2063");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.67, 3, "すっごい集中力…！\nもしかして、ヒデサイ\nおにムズ問題ほど\n燃える感じっしょ？", 3001, 6, 2, 2, 15, 22300124, 0, 3, 19, "vo_minigame_1012_result_2064");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 3, "きゃはっ、いい感じ！\nたくさん解けてるし\nベンキョーの成果\n…ってやつだね♪", 3001, 3, 2, 2, 10, 22300131, 0, 1, 14, "vo_minigame_1012_result_2067");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "10個以上〇だね♪\nヒデサイのおかげで\nうちも、ちょっち\n頭よくなったかな？", 3001, 2, 2, 2, 10, 22300132, 0, 1, 14, "vo_minigame_1012_result_2068");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.28, 2, "けっこー解けたよね？\nやっぱ〇増えると\nバイブス上がる～", 3001, 10, 2, 2, 10, 22300133, 0, 1, 14, "vo_minigame_1012_result_2069");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "ベンキョーってあれだね\nわかった気すると\nまあまあたのしーかも！", 3001, 2, 2, 2, 10, 22300134, 0, 2, 14, "vo_minigame_1012_result_2070");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.1, 2, "10個以上解けてる！？\nけっこーいいペースだよね？\nいい調子、いい調子～", 3001, 6, 2, 2, 10, 22300135, 0, 2, 14, "vo_minigame_1012_result_2071");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.13, 3, "けっこー解けてる！\nムズい問題もヒデサイと\n一緒なら怖くないね♪", 3001, 2, 2, 2, 10, 22300136, 0, 2, 14, "vo_minigame_1012_result_2072");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 7, "おにムズ問題でも教えるの\n超やさしーし、マジ感謝！\n一緒にがんばろーね♪", 3001, 7, 2, 2, 10, 22300137, 0, 3, 14, "vo_minigame_1012_result_2073");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 6, "おにムズなのに\n〇けっこーあるし\nヒデサイすごくない？", 3001, 6, 2, 2, 10, 22300138, 0, 3, 14, "vo_minigame_1012_result_2074");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.21, 5, "おにムズでこのペースは\nすごいんじゃ…？\nうちもがんばってついてくね！", 3001, 6, 2, 2, 10, 22300139, 0, 3, 14, "vo_minigame_1012_result_2075");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (1.94, 3, "悪くないよね？\nでもでも\nヒデサイとうちなら\nもっとできる気する！", 3001, 0, 2, 2, 5, 22300146, 0, 1, 9, "vo_minigame_1012_result_2078");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.28, 0, "もっと〇ほしーね…\n地道にやるしか\nないっぽいし\nもっかい教えてくれる？", 3001, 4, 2, 2, 5, 22300147, 0, 1, 9, "vo_minigame_1012_result_2079");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 4, "ベンキョーしたけど\nわかんないとこばっか…\nヒデサイセンセー、助けて～", 3001, 4, 2, 2, 5, 22300148, 0, 1, 9, "vo_minigame_1012_result_2080");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.67, 3, "やっぱムズかったね…\nでも次はもうちょい\nできそーな気がするよ！", 3001, 4, 2, 2, 5, 22300149, 0, 2, 9, "vo_minigame_1012_result_2081");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.68, 6, "問題ムズいし、この点数は\nありよりのありっしょ？\nえ、もっとできた感じ？", 3001, 10, 2, 2, 5, 22300150, 0, 2, 9, "vo_minigame_1012_result_2082");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 9, "どこ間違ったんだろ？\nうちさっぱりだった…\nやっぱムズいだけあるね", 3001, 9, 2, 2, 5, 22300151, 0, 2, 9, "vo_minigame_1012_result_2083");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.55, 3, "激ムズだけど\nやることは一緒だよね？\nうちもヒデサイについてくから\nコツコツがんばろ！", 3001, 0, 2, 2, 5, 22300152, 0, 3, 9, "vo_minigame_1012_result_2084");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.51, 6, "やっぱおにムズだね…\nそだ、迷ったら\nヒント使うのも\nありよりのあり？", 3001, 4, 2, 2, 5, 22300153, 0, 3, 9, "vo_minigame_1012_result_2085");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6.15, 5, "やっぱテストって\nなんとなくじゃ無理？\n覚えるしかないの？\nじゃあがんばるしかないね…", 3001, 9, 2, 2, 5, 22300154, 0, 3, 9, "vo_minigame_1012_result_2086");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.12, 9, "できたと思ったけど\nそーじゃなかった系？\nテストってマジきびしー…", 3001, 4, 2, 2, 1, 22300155, 6, 1, 4, "vo_minigame_1012_result_2087");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 4, "うーん…さっぱり！\nでも簡単な問題なんだよね…？\nもっかいやってみる？", 3001, 4, 2, 2, 1, 22300156, 6, 1, 4, "vo_minigame_1012_result_2088");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.28, 3, "うちらまだまだ\nベンキョーちうだし…\nこれからだよねっ？\nね、ヒデサイ！", 3001, 0, 2, 2, 1, 22300157, 0, 1, 4, "vo_minigame_1012_result_2089");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.89, 3, "ちょっとずつ覚えれば\nおーけーっしょ！\nうちと一緒に\nベンキョーだね！", 3001, 0, 2, 2, 1, 22300158, 0, 2, 4, "vo_minigame_1012_result_2090");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (5.45, 7, "うちベンキョー苦手でも\nヒデサイとベンキョー\nするのは好き！　だから\nもっかい教えてくれる？", 3001, 0, 2, 2, 1, 22300159, 0, 2, 4, "vo_minigame_1012_result_2091");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.29, 10, "覚えても、すぐ忘れるんだけど\nどしたらいい？\nあ、そーゆうとき\nフクシューする感じ？", 3001, 4, 2, 2, 1, 22300160, 3, 2, 4, "vo_minigame_1012_result_2092");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.64, 8, "ムズ過ぎ！\n頭パンクするかと思った…！\nヒデサイ、うちの頭\nふぅふぅして～", 3001, 4, 2, 2, 1, 22300161, 6, 3, 4, "vo_minigame_1012_result_2093");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.14, 5, "おにムズ過ぎてテンサゲ～\nでもヒデサイがんばってるし\nうちもがんばる！", 3001, 9, 2, 2, 1, 22300162, 0, 3, 4, "vo_minigame_1012_result_2094");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (6.59, 4, "ヒデサイと同じ点数で\nちょっち安心したかも\n一緒にがんばろーね！\n置いてっちゃやだよ？", 3001, 7, 2, 2, 1, 22300163, 0, 3, 4, "vo_minigame_1012_result_2095");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 3, "…まあ、これより下はないし\n次は大逆転\n点数爆上がりっしょ！", 3001, 3, 2, 2, 0, 22300164, 0, 1, 0, "vo_minigame_1012_result_2096");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.2, 10, "０点じゃん…\nそだ、次はえんぴつ転がして\n選ぶ作戦やってみる？", 3001, 9, 2, 2, 0, 22300165, 5, 1, 0, "vo_minigame_1012_result_2097");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 4, "考えるの無理な時あるよね…\nヒデサイもそーゆう\n感じだったの？", 3001, 4, 2, 2, 0, 22300166, 6, 1, 0, "vo_minigame_1012_result_2098");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.8, 2, "え、ヒデサイも０点？\nじゃあうちと一緒じゃん♪\nまあ焦んないで\nベンキョーしてこーよ！", 3001, 6, 2, 2, 0, 22300167, 3, 2, 0, "vo_minigame_1012_result_2099");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.22, 4, "むむむ～…０点…！\n覚えてもすぐ忘れちゃうし\nベンキョーってマジ大変", 3001, 9, 2, 2, 0, 22300168, 6, 2, 0, "vo_minigame_1012_result_2100");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.1, 0, "０点だね…\nでも、へーきへーき\nリベンジしたら、結果オーライ！", 3001, 4, 2, 2, 0, 22300169, 11, 2, 0, "vo_minigame_1012_result_2101");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (2.74, 2, "おやつ休憩して\nリベンジしよっ！\n甘いの食べたら、イケるっしょ！", 3001, 0, 2, 2, 0, 22300170, 3, 3, 0, "vo_minigame_1012_result_2102");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (3.0, 9, "ヒデサイでも\nおにムズな感じ？\nじゃあ、このテスト\n誰も解けなくない？", 3001, 6, 2, 2, 0, 22300171, 9, 3, 0, "vo_minigame_1012_result_2103");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (4.37, 2, "…あれ？\n０が〇に見えてきた！\nきゃはっ、ちょっち\nやる気出てきたかも！", 3001, 10, 2, 2, 0, 22300172, 0, 3, 0, "vo_minigame_1012_result_2104");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 0, "よーし、がんばるぞー", 1001, 0, 3, 2, 0, 23100101, 10, 0, 0, "vo_minigame_1012_gamestart_200");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "ベンキョー、\nベンキョー！", 1001, 2, 3, 2, 0, 23100102, 0, 0, 0, "vo_minigame_1012_gamestart_201");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 3, "ヒデサイ、よろ～", 1001, 3, 3, 2, 0, 23100103, 0, 0, 0, "vo_minigame_1012_gamestart_202");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.01, 0, "繰り返しがジューヨーだもんね♪", 1002, 0, 3, 2, 3, 23100201, 4, 0, -1, "vo_minigame_1012_gamestart_203");
