INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 6, "まあまあムズいらしーよ？", 1003, 6, 3, 2, 2, 23100303, 0, 0, 2, "vo_minigame_1012_gamestart_207");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 5, "おっけー、がんばってみる…！", 1003, 5, 3, 2, 2, 23100304, 0, 0, 2, "vo_minigame_1012_gamestart_208");
