INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 2, "もっかいベンキョーだね！", 1004, 2, 3, 2, 0, 23100402, 0, 0, 0, "vo_minigame_1012_gamestart_212");
INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 3, "キャルっちと\nベンキョーしてたの\n見ちゃった♪", 1005, 3, 3, 2, 0, 23100501, 0, 0, 0, "vo_minigame_1012_gamestart_213");
