INSERT INTO `v1_331f87fd07f5bfc09d6b75dd2eefc5c30acaf99d85522b9a86ab1f76bb50e34e` VALUES (0.0, 3, "かもーん！", 1101, 3, 3, 2, 0, 23110101, 0, 0, 0, "vo_minigame_1012_start_200");
